    for (let i = 0; i < rawName.length; i++) {
      const ch = rawName[i];
      filename += /[a-zA-Z0-9._-]/.test(ch) ? ch : '_';
    }

    msg.payload = Buffer.from(pdf);
    msg.headers = {
      'Content-Type': 'application/pdf',
      'Content-Disposition': 'attachment; filename="' + filename + '.pdf"'
    };
    msg.statusCode = 200;
    msg._responseTarget = 'export';
    node.send(msg);
